const express = require('express');
const bcrypt = require('bcryptjs'); // Used to hash passwords in MongoDB, used with middleware function 'async' below √
var jwt=require("jsonwebtoken");//for creating and verifying the JWT token. installed using npm install jsonwebtoken --save or yarn add jsonwebtoken if you use it as a library in your project, requires bcryptjs package too (bcrypt) √
const router = express.Router(); // to create new route handlers for our application and require('express').router() function return middleware/routes which help us set up the routing around Express by handling HTTP requests & responses in Node Js, similar as app object from other frameworks (like Angular etc.) √
const User =require("../models/User");// importing user model for validation of username and password. Assuming you have a 'user' schema or table with fields like "username", "password" in your database using mongoose ORM, replace it accordingly (if not)  √ 
router.post('/login', async function(req, res){//express middleware/route handler for POST request to /api/users and require express().Router() returns a new MiddleWare router with the specified path prefix which can be used in an application similar as app from other frameworks or services  √
  let user = await User.findOne({ username: req.body.username });// Finds first document within users collection where 'users' is your MongoDB database and "user" matches the value of field named ('usrenname') in body/request sent from client, returns a promise  √
  if(!user){ //if no user found with this username; response to such situation using res.status(401).send('User not Found'). This is for unauthorized users and should be responded as error message by setting status code at least equal or bigger than '5xx'  √
    return res.status(401).json({message: "user doesnot exist"});  //res.statis in express returns a response with the specified HTTP request method, ie (200 OK) and sends back JSON data to be used as body of outgoing message  √
 } else {// if user is found then we will check password using bcrypt's compare() function  return true on success which indicates that 'user.password_db == req.body._pwd', the hashed version stored in database, and should match with encrypted pw received from client (req body)
    let validPassword = await bcrypt.compare(req.body.password , user.password);  //comparing input password to that saved into db using 'bcrypt' compare() method which returns a promise  √ if not, then it will return false indicating wrong credentials and should be responded with an appropriate error message
    if (!validPassword){//if the encrypted version of submitted pw is incorrect. Then response user as such situation by setting status code to 401 (unauthorized). This can also indicate that login failed  √
      return res.status(401).json({message: "Invalid Password"}); //res in express returns a HTTP request method and sends back JSON data for use on the client's browser, similar to '200 OK'. The body of outgoing message can contain any information you want  √
    } else {// if password is correct then we will create JWT token. Here user id should be stored in payload  when creating a new one and it should match with the logged-in (authenticated) users's ID, using 'jwt', to sign these tokens which can generate them  √
      let accessToken = jwt.sign({id:user._id}, "yoursecretkey",{expiresIn:'1h'}); //the second argument is the secret key for signing and third parameter expiration time of token, here it's set to 60 minutes (or '1 hour')  √
      return res.json({accessToken: accessToken });//return JSON web Token on success using JWT module in Nodejs express should be responded with the created jwt and user id as a payload of token response from client side app, can use this to keep users logged-in till '1 hour'  √
    }  //end else block if password is correct then we will create json web Token. Here JWT module in Nodejs express should be responded with the created jwt and user id as a payload of token response from client side app, can use this to keep users logged-in till '1 hour'  √
  } // end if block for username not found or password incorrect   ^_/ it means when POST request is done in middleware above. The server will respond with JWT on successful login and the user id returned from mongoDB otherwise a error message would be sent back to client side app  √
});  //end of express post route handler for /api/login, you can use this as an endpoint similar or equal in your mobile application. It takes POST request body which contains 'username' and the encrypted password ('password') from clientside JavaScript code via HTTP requests made by browser client to server through API calls  √